# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from itsdangerous import URLSafeTimedSerializer
import os
from flask_mail import Mail, Message

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SECRET_KEY'] = 'secret_key'
db = SQLAlchemy(app)
mail_settings = {
    "MAIL_SERVER": 'smtp.gmail.com',
    "MAIL_PORT": 465,
    "MAIL_USE_TLS": False,
    "MAIL_USE_SSL": True,
    "MAIL_USERNAME": 'your_email@gmail.com',
    "MAIL_PASSWORD": 'your_password'
}
app.config.update(mail_settings)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)

@app.route('/reset-password', methods=['POST'])
def reset_password():
    email = request.json.get('email')
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    user = User.query.filter_by(email=email).first()
    if user is None:
        return jsonify({'error': 'No account with this email found'}), 404

    serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])
    token = serializer.dumps(user.id)

    msg = Message("Reset Password", sender="your_email@gmail.com", recipients=[email])
    msg.body = f"Click the link to reset your password: <a href='{request.url_root}/reset-password/{token}'>Reset Password</a>"
    mail.send(msg)
    
    user.reset_token = token
    db.session.commit()
    return jsonify({'message': 'Password reset link sent'}), 200

if __name__ == '__main__':
    app.run(debug=True)